/**
 * icon returns a stroked 24px SVG for a named glyph. Unknown names yield an
 * empty SVG rather than throwing, so callers stay simple.
 * @param name      one of the keys in PATHS
 * @param className the SVG class (default 'w-6 h-6')
 * @param filled    render with currentColor fill instead of none
 */
export function icon(name, className = 'w-6 h-6', filled = false) {
  const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
  svg.setAttribute('class', className);
  svg.setAttribute('viewBox', '0 0 24 24');
  svg.setAttribute('fill', filled ? 'currentColor' : 'none');
  svg.setAttribute('stroke', 'currentColor');
  svg.setAttribute('stroke-width', '1.8');
  svg.setAttribute('stroke-linecap', 'round');
  svg.setAttribute('stroke-linejoin', 'round');
  svg.innerHTML = pathMarkup(name);
  return svg;
}

/** pathMarkup wraps a named path string in <path> elements (handles 2-path icons). */
function pathMarkup(name) {
  const d = PATHS[name] || '';
  return d
    .split(' M')
    .map((seg, i) => `<path d="${i === 0 ? seg : 'M' + seg}"/>`)
    .join('');
}

/**
 * avatar builds the gradient-ring initials avatar used across the app.
 * @param name     the display name (first char becomes the initial)
 * @param sizeClass tailwind size classes for the outer ring
 */
export function avatar(name, sizeClass = 'w-9 h-9') {
  const initial = (name || '?').charAt(0).toUpperCase();
  return el('div', { class: `avatar-ring ${sizeClass}` }, [
    el('div', { class: 'avatar-inner text-sm' }, [initial]),
  ]);
}
